import json,base64,requests,msal

def load_connector():
    try:
        with open('/run/connector.json','r') as f:
            return json.load(f)
    except Exception as e:
        return {"error": f"Failed to load connector.json: {e}"}

def build_recipients(lst):
    return [{"emailAddress": {"address": str(addr).strip()}} for addr in (lst or []) if isinstance(addr, str) and str(addr).strip()]

def map_val(val, mapping):
    return mapping.get(str(val).lower(), mapping.get('default'))

def main():
    data = load_connector()
    if isinstance(data, dict) and 'error' in data:
        print(json.dumps({"ok": False, "error": data['error']}))
        return
    cfg = data.get('configuration', {})
    auth = data.get('auth', {})
    tenant_id = str(auth.get('tenantId', '')).strip()
    client_id = str(auth.get('clientId', '')).strip()
    client_secret = str(auth.get('clientSecret', '')).strip()
    from_mailbox = str(cfg.get('fromMailbox', '')).strip()
    subject = str(cfg.get('subject', '')).strip()
    body = str(cfg.get('body', ''))
    body_type = str(cfg.get('bodyType', 'html'))
    to = cfg.get('to', [])
    cc = cfg.get('cc', [])
    bcc = cfg.get('bcc', [])
    reply_to = cfg.get('replyTo', [])
    importance = str(cfg.get('importance', 'normal'))
    save_to_sent = bool(cfg.get('saveToSentItems', True))
    dry_run = bool(cfg.get('dryRun', False))
    attachments = cfg.get('attachments', [])
    errors = []
    for name, val in [('tenantId', tenant_id), ('clientId', client_id), ('clientSecret', client_secret), ('fromMailbox', from_mailbox), ('subject', subject), ('body', body)]:
        if not val:
            errors.append(f"Missing required field: {name}")
    if not isinstance(to, list) or len(build_recipients(to)) == 0:
        errors.append("Configuration 'to' must be a non-empty array of email strings.")
    if errors:
        print(json.dumps({"ok": False, "error": "; ".join(errors)}))
        return
    body_type_map = {"html": "HTML", "text": "Text", "default": "HTML"}
    importance_map = {"low": "Low", "normal": "Normal", "high": "High", "default": "Normal"}
    message = {
        "subject": subject,
        "body": {"contentType": map_val(body_type, body_type_map), "content": body},
        "toRecipients": build_recipients(to)
    }
    if isinstance(cc, list) and cc:
        message["ccRecipients"] = build_recipients(cc)
    if isinstance(bcc, list) and bcc:
        message["bccRecipients"] = build_recipients(bcc)
    if isinstance(reply_to, list) and reply_to:
        message["replyTo"] = build_recipients(reply_to)
    # Attachments: expecting objects with name, contentType, contentBytes (base64)
    if isinstance(attachments, list) and attachments:
        msg_attachments = []
        for att in attachments:
            try:
                name = str(att.get('name', '')).strip()
                content_type = str(att.get('contentType', 'application/octet-stream'))
                content_bytes = str(att.get('contentBytes', '')).strip()
                if name and content_bytes:
                    msg_attachments.append({"@odata.type": "#microsoft.graph.fileAttachment", "name": name, "contentType": content_type, "contentBytes": content_bytes})
            except Exception:
                continue
        if msg_attachments:
            message["attachments"] = msg_attachments
    payload = {"message": message, "saveToSentItems": save_to_sent}
    if dry_run:
        print(json.dumps({"ok": True, "dryRun": True, "payload": payload}))
        return
    try:
        authority = f"https://login.microsoftonline.com/{tenant_id}"
        app = msal.ConfidentialClientApplication(client_id, authority=authority, client_credential=client_secret)
        token_result = app.acquire_token_for_client(scopes=["https://graph.microsoft.com/.default"])
        if 'access_token' not in token_result:
            print(json.dumps({"ok": False, "error": "Failed to acquire token", "details": token_result}))
            return
        access_token = token_result['access_token']
    except Exception as e:
        print(json.dumps({"ok": False, "error": f"Auth exception: {e}"}))
        return
    url = f"https://graph.microsoft.com/v1.0/users/{from_mailbox}/sendMail"
    headers = {"Authorization": f"Bearer {access_token}", "Content-Type": "application/json"}
    try:
        resp = requests.post(url, headers=headers, data=json.dumps(payload), timeout=30)
        if resp.status_code in (202, 200):
            print(json.dumps({"ok": True, "statusCode": resp.status_code, "sent": {"from": from_mailbox, "to": to, "cc": cc, "bcc": bcc}, "saveToSentItems": save_to_sent}))
        else:
            try:
                err = resp.json()
            except Exception:
                err = {"text": resp.text}
            print(json.dumps({"ok": False, "statusCode": resp.status_code, "error": err}))
    except Exception as e:
        print(json.dumps({"ok": False, "error": f"Request exception: {e}"}))

if __name__ == '__main__':
    main()
